        ("WH-002", "Warehouse B — South"),
        ("WH-003", "Warehouse C — East"),
        ("WH-004", "Warehouse D — West"),
    ];

    public string CurrentWarehouseId { get; private set; } = Warehouses[0].Id;

    public string CurrentWarehouseName =>
        Warehouses.First(w => w.Id == CurrentWarehouseId).Name;

    public int LowStockAlertCount { get; private set; }

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (Warehouses.All(w => w.Id != warehouseId))
            return;

        CurrentWarehouseId = warehouseId;
        LowStockAlertCount = 0;
        NotifyStateChanged();
    }

    public void SetAlertCount(int count)
    {
        LowStockAlertCount = count;
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

