@page "/dashboard"
@rendermode InteractiveServer
@using sv_fda3eb5d1520458fbb46f86491a0186d.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="text-muted mb-0">ID: @WarehouseState.CurrentWarehouseId</p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-bg-@(WarehouseState.LowStockAlertCount > 0 ? "danger" : "success")">
            <div class="card-body text-center">
                <h2 class="display-4">@WarehouseState.LowStockAlertCount</h2>
                <p class="mb-0">Low-Stock Alerts</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-info">
            <div class="card-body text-center">
                <h2 class="display-4">—</h2>
                <p class="mb-0">Pending Orders</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card text-bg-secondary">
            <div class="card-body text-center">
                <h2 class="display-4">—</h2>
                <p class="mb-0">Shipments Today</p>
            </div>
        </div>
    </div>
</div>

<p class="text-muted mt-3">
    <small>Alert count refreshes every 10 seconds. Last checked: @_lastChecked?.ToString("T")</small>
</p>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime? _lastChecked;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnStateChanged;
        await PollAlertCountAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await PollAlertCountAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose.
        }
    }

    private async Task PollAlertCountAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
        WarehouseState.SetAlertCount(count);
    }

    private void OnStateChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnStateChanged;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

